@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>
</div>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow" disabled="@(!hasUnsavedChanges)">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private DateTime? lastSavedAt;
    private bool hasUnsavedChanges;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    private const string StorageKey = "notepad-content";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", $"./{Assets["Components/Pages/Notepad.razor.js"]}");

            var stored = await module.InvokeAsync<string?>("load", StorageKey);
            if (!string.IsNullOrEmpty(stored))
            {
                content = stored;
                savedContent = stored;
                StateHasChanged();
            }

            autoSaveTimer = new System.Threading.Timer(
                async _ => await InvokeAsync(AutoSave), null,
                TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }
    }

    private async Task OnContentChanged()
    {
        hasUnsavedChanges = content != savedContent;
        if (module is not null)
        {
            await module.InvokeVoidAsync("setUnsaved", hasUnsavedChanges);
        }
    }

    private async Task AutoSave()
    {
        if (hasUnsavedChanges)
        {
            await Save();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("save", StorageKey, content);
            savedContent = content;
            hasUnsavedChanges = false;
            lastSavedAt = DateTime.Now;
            await module.InvokeVoidAsync("setUnsaved", false);
        }
    }

    private async Task Clear()
    {
        content = string.Empty;
        savedContent = string.Empty;
        hasUnsavedChanges = false;
        lastSavedAt = null;

        if (module is not null)
        {
            await module.InvokeVoidAsync("remove", StorageKey);
            await module.InvokeVoidAsync("setUnsaved", false);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }

        if (module is not null)
        {
            await module.InvokeVoidAsync("setUnsaved", false);
            await module.DisposeAsync();
        }
    }
}

function onBeforeUnload(e) {
    e.preventDefault();
}

export function save(key, value) {
    localStorage.setItem(key, value);
}

export function load(key) {
    return localStorage.getItem(key);
}

export function remove(key) {
    localStorage.removeItem(key);
}

export function setUnsaved(unsaved) {
    if (unsaved) {
        window.addEventListener("beforeunload", onBeforeUnload);
    } else {
        window.removeEventListener("beforeunload", onBeforeUnload);
    }
}

